import{_ as a,o as i,c as t,ak as e}from"./chunks/framework.DMc2NN9G.js";const b=JSON.parse('{"title":"手机号加密方案","description":"","frontmatter":{},"headers":[],"relativePath":"项目实战/高阶/小黄书/07.⼿机号加密方案.md","filePath":"项目实战/高阶/小黄书/07.⼿机号加密方案.md","lastUpdated":0}'),h={name:"项目实战/高阶/小黄书/07.⼿机号加密方案.md"};function n(l,s,d,r,p,k){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="手机号加密方案" tabindex="-1">手机号加密方案 <a class="header-anchor" href="#手机号加密方案" aria-label="Permalink to “手机号加密方案”">​</a></h1><h2 id="一、明文存储存在以下问题" tabindex="-1">一、明文存储存在以下问题 <a class="header-anchor" href="#一、明文存储存在以下问题" aria-label="Permalink to “一、明文存储存在以下问题”">​</a></h2><p>用户的手机号存储采用的是最原始的明文存储，这会有存在极大的风险性问题。假如某天有人故意将这份数据导出到外边拿去贩卖，那就是个很大的问题。</p><h2 id="二、业内常用的加密处理策略" tabindex="-1">二、业内常用的加密处理策略 <a class="header-anchor" href="#二、业内常用的加密处理策略" aria-label="Permalink to “二、业内常用的加密处理策略”">​</a></h2><h3 id="对称加密算法-加密解密用同一密钥" tabindex="-1">对称加密算法（加密解密用同一密钥） <a class="header-anchor" href="#对称加密算法-加密解密用同一密钥" aria-label="Permalink to “对称加密算法（加密解密用同一密钥）”">​</a></h3><p>对称加密的核心特点是效率极高（计算量小），适合短数据、高频次加解密场景，是手机号 / 邮箱加密的主流选择。</p><table tabindex="0"><thead><tr><th>算法</th><th>密钥长度</th><th>安全性</th><th>效率</th><th>可逆性</th><th>适用场景</th></tr></thead><tbody><tr><td>AES（推荐）</td><td>128/192/256 位</td><td>极高（256 位可抗量子攻击）</td><td>极快</td><td>是</td><td>短数据</td></tr><tr><td>DES</td><td>56 位</td><td>极低（已被暴力破解）</td><td>较快</td><td>是</td><td>历史遗留</td></tr><tr><td>3DES</td><td>168 位（3 个 56 位密钥）</td><td>中（安全性低于 AES）</td><td>较慢（AES 的 1/3）</td><td>是</td><td>需兼容</td></tr></tbody></table><h3 id="非对称加密算法-公钥加密、私钥解密" tabindex="-1">非对称加密算法（公钥加密、私钥解密） <a class="header-anchor" href="#非对称加密算法-公钥加密、私钥解密" aria-label="Permalink to “非对称加密算法（公钥加密、私钥解密）”">​</a></h3><p>非对称加密的核心特点是安全性高（密钥分离，公钥可公开），但效率极低（计算量是对称加密的 100-1000 倍），适合小数据量、低频次场景。</p><table tabindex="0"><thead><tr><th>算法</th><th>密钥长度</th><th>安全性</th><th>效率</th><th>可逆性</th></tr></thead><tbody><tr><td>RSA</td><td>2048 位及以上</td><td>高</td><td>慢</td><td>是</td></tr><tr><td>ECC</td><td>256 位</td><td>极高</td><td>中（比 RSA 快 3-5 倍）</td><td>是</td></tr></tbody></table><p>结合手机号 / 邮箱的短数据、高频次、需还原的特点，我们可以尝试使用 AES 算法来实现。</p><h2 id="三、结论" tabindex="-1">三、结论 <a class="header-anchor" href="#三、结论" aria-label="Permalink to “三、结论”">​</a></h2><p><strong>AES 算法（推荐 AES-128-GCM 模式）</strong></p><p>理由：效率最高（微秒级处理 11 位手机号），安全性符合国际标准（NIST 认证），GCM 模式自带&quot;加密 + 完整性校验&quot;（防止数据被篡改），且支持轻量化实现（适合服务器 / 移动端）。每次生成的结果都会随机变化，难以破解。</p><p>注意：需严格管理对称密钥（如用密钥管理系统 KMS 存储，定期轮换）。</p><h2 id="四、加密数据在数据库层如何做检索" tabindex="-1">四、加密数据在数据库层如何做检索 <a class="header-anchor" href="#四、加密数据在数据库层如何做检索" aria-label="Permalink to “四、加密数据在数据库层如何做检索”">​</a></h2><h3 id="利用数据库内置加解密函数" tabindex="-1">利用数据库内置加解密函数 <a class="header-anchor" href="#利用数据库内置加解密函数" aria-label="Permalink to “利用数据库内置加解密函数”">​</a></h3><p>在 MySQL 存储层其实也有内置支持一些专门用于加解密使用的特殊函数，例如 MD5，DES，AES 等。我们可以对 SQL 进行修改成如下案例：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, AES_decrypt(phone,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;密钥&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_user_phone;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>ps：MySQL 内部的 AES_decrypt 函数默认返回的是二进制格式的数据，因此底层存储需要用 blob 或者 VARBINARY 格式来存储。</p><p><strong>==性能极差，不推荐。会导致全表扫描，对于大数据量存储的场景不适合==。</strong></p><p>如果足够厉害，可以对 MySQL 的底层源代码直接做修改，自定义一套加解密数据的检索能力内置进去，不过这样做的开发难度极高。而且聘请一位懂这方面技术的专家的成本也是极高的。</p><h3 id="在应用层做加解密处理" tabindex="-1">在应用层做加解密处理 <a class="header-anchor" href="#在应用层做加解密处理" aria-label="Permalink to “在应用层做加解密处理”">​</a></h3><p>可以通过 MyBatis 框架，给我们的手机号，邮件这样的字段增加一个注解，然后在 ORM 框架层做注解判断的拦截处理。如果命中，则利用自定义的算法工具做加解密。DB 层依然存储的是密文本身，然后解密的密钥通过应用层配置来控制。这样即使说数据脱库了，但是操作者不知道密钥，依然无法解密。</p><blockquote><p><strong>对于精确查询可以支持，但是模糊查询类型不好支持。</strong></p></blockquote><h3 id="分段式存储" tabindex="-1">分段式存储 <a class="header-anchor" href="#分段式存储" aria-label="Permalink to “分段式存储”">​</a></h3><p>还是继续基于应用层去做加解密式的处理，但是我们对于底层 DB 的存储做一些扩展。例如手机号为：<code>099 784 927</code>，我们将其拆成：099，784，927，然后利用工具加密后的密文假设为：</p><table tabindex="0"><thead><tr><th>号段内容</th><th>加密后</th></tr></thead><tbody><tr><td>099</td><td>H923hbyubqwfty</td></tr><tr><td>784</td><td>89h3iuFZsHwe3a</td></tr><tr><td>927</td><td>QwGkagj8h7834G</td></tr></tbody></table><p>然后 DB 层将这些分段后的加密内容一并保存起来。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">insert into</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_user_phone (encrypt_phone_str,encrypt_block) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">values</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;z6EDHN5400Ht+TbIJzC6GlnlYVWKx4coQngcynBPWhXU6Ev0rYSM&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;H923hbyubqwfty,89h3iuFZsHwe3a,QwGkagj8h7834G&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样后续做模糊搜索能力的时候，我们可以提供出基于加密后数据段的简单检索能力。</p><p>例如：按照手机的前三位或者手机号的末尾三位号码做检索。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 前三位手机号加密后的模糊检索</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_user_phone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> encrypt_block </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">like</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;H923hbyubqwfty,%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 后三位手机号加密后的模糊检索</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_user_phone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> encrypt_block </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">like</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%,QwGkagj8h7834G&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>==<strong>可以应付模糊检索的能力，但是只能解决部分场景下的模糊检索功能，只适合用于简单加密逻辑场景中，如果底层是类似于 AES 这种高强度的加密算法的话，分段存储思路不适合。</strong>==</p><h2 id="五、小结" tabindex="-1">五、小结 <a class="header-anchor" href="#五、小结" aria-label="Permalink to “五、小结”">​</a></h2><p>目前小绿书阶段还没有需要做到手机号这些数据做模糊查询的场景，分段式存储的方案可以保留，暂时只需要做到应用层基于 ORM 框架实现加解密逻辑处理即可。</p>`,36)])])}const c=a(h,[["render",n]]);export{b as __pageData,c as default};
